qry:select.qry:xquery:
			for $r in sql('
	SELECT PER.oi_personal, PER20_TIPOS_DOC.c_tipo_documento, PER.c_nro_documento, PER.d_ape_y_nom, SEC.policy
	FROM 
		PER01_PERSONAL as PER,  
		{%?('##activos##'='1') {% PER02_PERSONAL_EMP as LEG,%} {% %} %}
		PER20_TIPOS_DOC, NMD_SECURITY(class=\'NucleusRH.Base.Personal.Legajo.PERSONAL\') AS SEC
	JOIN 
		{%?('##activos##'='1') {% PER.oi_personal LEFT OUTER LEG.oi_personal,%} {% %} %}
		PER.oi_tipo_documento INNER PER20_TIPOS_DOC.oi_tipo_documento,
		PER.oi_personal LEFT OUTER SEC.id
	WHERE 1=1                        
		{%?('##activos##'='1') {% and LEG.oi_indic_activo= \'1\' %} {% %} %}
		{%?('##nombre##'!='') {% and contain(UCASE(PER.d_ape_y_nom), UCASE(\'##nombre##\')) %} {% %} %}
		{%?('##documento##'!='') {% and contain(PER.c_nro_documento, \'##documento##\') %} {% %} %}
		{%?('##sexo##'!='') {% and PER.c_sexo = \'##sexo##\' %} {% %} %}
		{%?('##grupo_sanguineo##'!='') {% and PER.oi_grupo_sanguineo = ##grupo_sanguineo## %} {% %} %}
		{%?('##sin_legajo##'='1') {% and PER.oi_personal not in (select per02_personal_emp.oi_personal from per02_personal_emp) %} {% %} %}
	ORDER BY d_ape_y_nom ASC
')/ROWS/ROW

			for $r in sql('
	SELECT 
		PER.oi_personal, 
		PER20_TIPOS_DOC.c_tipo_documento, 
		PER.c_nro_documento, 
		PER.d_ape_y_nom, SEC.policy
	FROM 
		PER01_PERSONAL as PER, 
		PER02_PERSONAL_EMP as LEG,
		PER20_TIPOS_DOC,
		NMD_SECURITY(class=\'NucleusRH.Base.Personal.LegajoEmpresa.PERSONAL_EMP\') as SEC
	JOIN 
		PER.oi_personal LEFT OUTER LEG.oi_personal,
		PER.oi_tipo_documento INNER PER20_TIPOS_DOC.oi_tipo_documento,
		PER.oi_personal LEFT OUTER SEC.id
	WHERE 1=1 
	{%?('##activos##'='1') {% and LEG.oi_indic_activo= \'1\' %} {% %} %}
	{%?('##empresa##'!='') {% and LEG.oi_empresa = ##empresa## %} {% %} %}			
	{%?('##leg_desde1##'!='' AND '##leg_hasta1##'!='') 
		{% and (LEG.e_numero_legajo >= ##leg_desde1## AND LEG.e_numero_legajo <= ##leg_hasta1## %} 
		{% %} 
	%}
	{%?('##leg_desde2##'!='' AND '##leg_hasta2##'!='') 
		{% or LEG.e_numero_legajo >= ##leg_desde2## AND LEG.e_numero_legajo <= ##leg_hasta2## %} 
		{% %} 
	%}
	{%?('##leg_desde3##'!='' AND '##leg_hasta3##'!='') 
		{% or LEG.e_numero_legajo >= ##leg_desde3## AND LEG.e_numero_legajo <= ##leg_hasta3## %} 
		{% %} 
	%}
	{%?('##leg_desde1##'!='' OR '##leg_hasta1##'!='' OR '##leg_desde2##'!='' OR '##leg_hasta2##'!='' OR '##leg_desde3##'!='' OR '##leg_hasta3##'!='') 									
		{% ) %} 
		{%	{%?('##leg_list##'!='') 
					{% AND 1 = 2%}
					{% %}
				%}
		%}
	%}
	{%?('##indic_activo##'!='') {% and LEG.oi_indic_activo = ##indic_activo## %} {% %} %}
	{%?('##egresado##'='1') {% and isnotnull(LEG.f_egreso) %} {% %} %}
	{%?('##egresado##'='0') {% and isnull(LEG.f_egreso) %} {% %} %}
	{%?('##tipo_per##'!='') {% and LEG.oi_tipo_personal = ##tipo_per## %} {% %} %}
	{%?('##forma_pago##'!='') {% and LEG.oi_forma_pago = ##forma_pago## %} {% %} %}			
	{%?('##fecha_desde##'!='') {% and LEG.f_ingreso >= {Datetime(\'##fecha_desde##\')} %} {% %} %}
	{%?('##fecha_hasta##'!='') {% and LEG.f_ingreso <= {Datetime(\'##fecha_hasta##\')} %} {% %} %}
	{%?('##leg_list##'!='') 
		{%

		UNION SELECT 
			PER.oi_personal, 
			PER20_TIPOS_DOC.c_tipo_documento, 
			PER.c_nro_documento, 
			PER.d_ape_y_nom, 
			SEC.policy
		FROM 
			PER01_PERSONAL as PER, 
			PER02_PERSONAL_EMP as LEG,
			PER20_TIPOS_DOC,
			NMD_SECURITY(class=\'NucleusRH.Base.Personal.LegajoEmpresa.PERSONAL_EMP\') as SEC
		JOIN 
			PER.oi_personal LEFT OUTER LEG.oi_personal,
			PER.oi_tipo_documento INNER PER20_TIPOS_DOC.oi_tipo_documento,
			PER.oi_personal LEFT OUTER SEC.id
		WHERE 
			1=1 
			{%?('##activos##'='1') {% and LEG.oi_indic_activo= \'1\' %} {% %} %}
			{%?('##empresa##'!='') {% and LEG.oi_empresa = ##empresa## %} {% %} %}			
			{%?('##indic_activo##'!='') {% and LEG.oi_indic_activo = ##indic_activo## %} {% %} %}
			{%?('##egresado##'='1') {% and isnotnull(LEG.f_egreso) %} {% %} %}
			{%?('##egresado##'='0') {% and isnull(LEG.f_egreso) %} {% %} %}
			{%?('##tipo_per##'!='') {% and LEG.oi_tipo_personal = ##tipo_per## %} {% %} %}
			{%?('##forma_pago##'!='') {% and LEG.oi_forma_pago = ##forma_pago## %} {% %} %}			
			{%?('##fecha_desde##'!='') {% and LEG.f_ingreso >= {Datetime(\'##fecha_desde##\')} %} {% %} %}
			{%?('##fecha_hasta##'!='') {% and LEG.f_ingreso <= {Datetime(\'##fecha_hasta##\')} %} {% %} %}
			AND LEG.e_numero_legajo in (##leg_list##) 
			%} 
			{% %} 
	%}
	ORDER BY d_ape_y_nom ASC
')/ROWS/ROW

			for $r in sql('
	SELECT PER.oi_personal, PER20_TIPOS_DOC.c_tipo_documento, PER.c_nro_documento, PER.d_ape_y_nom, SEC.policy
	FROM 
		PER01_PERSONAL as PER, 
		PER02_PERSONAL_EMP as LEG,
		PER20_TIPOS_DOC, NMD_SECURITY(class=\'NucleusRH.Base.Personal.Legajo.PERSONAL\') AS SEC
		{%?('##estructura##'!='') {% , ORG02_ESTRUC_PERS as ESTR %} {% %} %}
		{%?('##ubicacion_desde##'!='' OR '##ubicacion_hasta##'!='') {% , ORG03_UBICACIONES as UBI %} {% %} %}
		{%?('##convenio##'!='' OR '##categoria##'!='') {% , ORG18_CATEGORIAS AS CAT %} {% %} %}
		{%?('##contrato##'!='') {% , PER28_CONTRATOS AS CON %} {% %} %}
	JOIN                                                   
		PER.oi_personal INNER LEG.oi_personal,
		PER.oi_tipo_documento INNER PER20_TIPOS_DOC.oi_tipo_documento,
		PER.oi_personal LEFT OUTER SEC.id
		{%?('##estructura##'!='') {% , ESTR.oi_personal_emp INNER LEG.oi_personal_emp %} {% %} %}
		{%?('##ubicacion_desde##'!='' OR '##ubicacion_hasta##'!='') {% , UBI.oi_ubicacion INNER LEG.oi_ubicacion %} {% %} %}			
		{%?('##convenio##'!='' OR '##categoria##'!='') {% , LEG.oi_categoria_ult INNER CAT.oi_categoria %} {% %} %}     
		{%?('##contrato##'!='') {% , LEG.oi_contrato LEFT OUTER CON.oi_contrato %} {% %} %}     			
	WHERE 1=1    
		{%?('##activos##'='1') {% and LEG.oi_indic_activo= \'1\' %} {% %} %}
		{%?('##empresa##'!='') {% and LEG.oi_empresa = ##empresa## %} {% %} %}
		{%?('##centro_costo##'!='') {% and LEG.oi_ctro_costo_ult = ##centro_costo## %} {% %} %}
		{%?('##convenio##'!='') {% and CAT.oi_convenio = ##convenio## %} {% %} %}
		{%?('##categoria##'!='') {% and LEG.oi_categoria_ult = ##categoria## %} {% %} %}
		{%?('##contrato##'!='') {% and LEG.oi_contrato = ##contrato## %} {% %} %}
		{%?('##ubicacion_desde##'!='') 
			{% 
				and UBI.c_ubicacion >= {#PARAM:@cubi_desde}
			%} {% %} %}
		{%?('##ubicacion_hasta##'!='') 
			{% 
				and UBI.c_ubicacion <= {#PARAM:@cubi_hasta}
			%} {% %} %}
		{%?('##estructura##'!='') {% and ESTR.oi_estructura in({%=#PARAM:@estrs%}) %} {% %} %}
		{%?('##soloconvenio##'='1') {% and LEG.oi_categoria_ult not in (select org18_categorias.oi_categoria from org18_categorias, org18_convenios join  org18_categorias.oi_convenio INNER org18_convenios.oi_convenio WHERE org18_convenios.c_convenio = \'00\')%} {% %} %}
	ORDER BY d_ape_y_nom ASC
')/ROWS/ROW

form:Form.form:Scripts:
		function SendToServer()
{       
	GetProxy().StoreService().SetUserStore("PER_IDsPersonas", array2stringcustom(arrB, "ROWS", "ROW"));
	return true;
}

function Filtrar()
{               
 	if (Ctrl("list2").TotalRowsCount()==0)
 	{             
 		alert("No hay personas filtradas.");
 		return false;
 	}

 	if (Ctrl("list2").TotalRowsCount()>100)
 	{             
 		alert("Hay demasiados registros seleccionados, afine la búsqueda.");
 		return false;
 	}
	SendToServer();
	Ctrl("main").DoEvent("FILTER");
}

function enable_custom_buttons()
{
	if (Ctrl("list2"))
		CtrlEnabled("btnFILTER", Ctrl("list2").TotalRowsCount()?true:false);
}
